#include <stdio.h>

int main(void) {
    int n, limit;
    int count = 0;

    if (scanf("%d %d", &n, &limit) != 2) {
        return 0;
    }

    for (int i = 0; i < n; i++) {
        int x;
        if (scanf("%d", &x) != 1) {
            return 0;
        }
        if (x > limit) {
            count++;
        }
    }

    printf("%d\n", count);
    return 0;
}
